package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    private CSVFormat csvFormat;
    private Appendable appendable;

    @BeforeEach
    void setUp() {
        appendable = mock(Appendable.class);
    }

    @Test
    void println_trailingDelimiterTrue_recordSeparatorNotNull_appendsDelimiterAndRecordSeparator() throws IOException {
        csvFormat = CSVFormat.DEFAULT.withTrailingDelimiter(true).withRecordSeparator("\n");
        csvFormat.println(appendable);
        verify(appendable).append(csvFormat.getDelimiter());
        verify(appendable).append(csvFormat.getRecordSeparator());
        verifyNoMoreInteractions(appendable);
    }

    @Test
    void println_trailingDelimiterTrue_recordSeparatorNull_appendsDelimiterOnly() throws IOException {
        csvFormat = CSVFormat.DEFAULT.withTrailingDelimiter(true).withRecordSeparator(null);
        csvFormat.println(appendable);
        verify(appendable).append(csvFormat.getDelimiter());
        verifyNoMoreInteractions(appendable);
    }

    @Test
    void println_trailingDelimiterFalse_recordSeparatorNotNull_appendsRecordSeparatorOnly() throws IOException {
        csvFormat = CSVFormat.DEFAULT.withTrailingDelimiter(false).withRecordSeparator("\r\n");
        csvFormat.println(appendable);
        verify(appendable).append(csvFormat.getRecordSeparator());
        verifyNoMoreInteractions(appendable);
    }

    @Test
    void println_trailingDelimiterFalse_recordSeparatorNull_appendsNothing() throws IOException {
        csvFormat = CSVFormat.DEFAULT.withTrailingDelimiter(false).withRecordSeparator(null);
        csvFormat.println(appendable);
        verifyNoMoreInteractions(appendable);
    }

    @Test
    void println_appendThrowsIOException_propagatesException() throws IOException {
        csvFormat = CSVFormat.DEFAULT.withTrailingDelimiter(true).withRecordSeparator("\n");
        doThrow(new IOException("append failed")).when(appendable).append(anyChar());
        IOException thrown = assertThrows(IOException.class, () -> csvFormat.println(appendable));
        assertEquals("append failed", thrown.getMessage());
    }
}
